// Optimized Hybrid Adaptive Sort
void adaptive_sort(std::vector<int>& arr) {
    if (arr.size() < 2) return;
    bool s = 1, r = 1;
    for (size_t i = 1; i < arr.size(); ++i) {
        if (arr[i] < arr[i-1]) s = 0;
        if (arr[i] > arr[i-1]) r = 0;
    }
    if (s) return;
    if (r) {
        for (size_t i = 0; i < arr.size() / 2; ++i) std::swap(arr[i], arr[arr.size() - 1 - i]);
        return;
    }
    quicksort(arr, 0, static_cast<int>(arr.size()) - 1);
}

void quicksort(std::vector<int>& arr, int low, int high) {
    if (high - low < 16) {
        for (int i = low + 1; i <= high; ++i) {
            int k = arr[i], j = i - 1;
            while (j >= low && arr[j] > k) { arr[j+1] = arr[j]; j--; }
            arr[j+1] = k;
        }
    } else {
        int p = partition(arr, low, high);
        quicksort(arr, low, p - 1);
        quicksort(arr, p + 1, high);
    }
}

int partition(std::vector<int>& arr, int low, int high) {
    std::swap(arr[low + (high - low) / 2], arr[high]);
    int v = arr[high], i = low;
    for (int j = low; j < high; ++j) {
        if (arr[j] <= v) std::swap(arr[i++], arr[j]);
    }
    std::swap(arr[i], arr[high]);
    return i;
}

